    "typeDeclaration": "import type { ApplicationLoadBalancerCustomTriggerProps } from 'stacktape';\n\n// [!code focus-start]\ntype ApplicationLoadBalancerCustomTrigger = {\n  properties: ApplicationLoadBalancerCustomTriggerProps;\n};\n// [!code focus-end]"
