                  "required": false,
                  "shortDescription": "<p> Number of reader instances in the Aurora Serverless v2 cluster.</p>\n",
                  "longDescription": "<p>Aurora Serverless v2 always has one writer instance. This value adds additional readers\n(<code>0</code> means writer only, <code>2</code> means writer + 2 readers).</p>\n",
                  "defaultValue": "0",
                  "typeInfo": {
                    "kind": "primitive",
                    "types": [
                      "number"
                    ]
                  }
