  "CustomKafkaEventSource": {
    "definitionName": "CustomKafkaEventSource",
    "properties": [
      {
        "name": "authentication",
        "required": true,
        "shortDescription": "<p> The authentication method for connecting to the Kafka cluster.</p>\n",
        "longDescription": "<ul>\n<li><code>SASL</code>: Authenticate using a username and password (PLAIN or SCRAM).</li>\n<li><code>MTLS</code>: Authenticate using a client-side TLS certificate.</li>\n</ul>\n",
        "typeInfo": {
          "kind": "union",
          "discriminator": null,
          "branches": [
            {
              "label": "KafkaSASLAuth",
              "typeName": "KafkaSASLAuth",
              "properties": [
                {
                  "name": "authenticationSecretArn",
                  "required": true,
                  "shortDescription": "<p> The ARN of a secret containing the Kafka credentials.</p>\n",
                  "longDescription": "<p>The secret must be a JSON object with <code>username</code> and <code>password</code> keys.\nYou can create secrets using the <code>stacktape secret:create</code> command.</p>\n",
                  "typeInfo": {
                    "kind": "primitive",
                    "types": [
                      "string"
                    ]
                  }
                }
              ]
            },
            {
              "label": "KafkaMTLSAuth",
              "typeName": "KafkaMTLSAuth",
              "properties": [
                {
                  "name": "clientCertificate",
                  "required": true,
                  "shortDescription": "<p> The ARN of a secret containing the client certificate.</p>\n",
                  "longDescription": "<p>This secret should contain the certificate chain (X.509 PEM), private key (PKCS#8 PEM), and an optional private key password.\nYou can create secrets using the <code>stacktape secret:create</code> command.</p>\n",
                  "typeInfo": {
                    "kind": "primitive",
                    "types": [
                      "string"
                    ]
                  }
                },
                {
                  "name": "serverRootCaCertificate",
                  "required": false,
                  "shortDescription": "<p> The ARN of a secret containing the server&#39;s root CA certificate.</p>\n",
                  "longDescription": "<p>You can create secrets using the <code>stacktape secret:create</code> command.</p>\n",
                  "typeInfo": {
                    "kind": "primitive",
                    "types": [
                      "string"
                    ]
                  }
                }
              ]
            }
          ]
        }
      },
      {
        "name": "bootstrapServers",
        "required": true,
        "shortDescription": "<p> A list of <code>host:port</code> addresses for your Kafka brokers.</p>\n",
        "longDescription": "",
        "typeInfo": {
          "kind": "array",
          "itemType": {
            "kind": "primitive",
            "types": [
              "string"
            ]
          }
        }
      },
      {
        "name": "topicName",
        "required": true,
        "shortDescription": "<p> The name of the Kafka topic to consume messages from.</p>\n",
        "longDescription": "",
        "typeInfo": {
          "kind": "primitive",
          "types": [
            "string"
          ]
        }
      }
    ],
    "stats": {
      "requiredCount": 3,
      "optionalCount": 0
    },
    "typeDeclaration": "import type { KafkaMTLSAuth, KafkaSASLAuth } from 'stacktape';\n\n// [!code focus-start]\ntype CustomKafkaEventSource = {\n  /** The authentication method for connecting to the Kafka cluster. */\n  authentication: CustomKafkaEventSourceAuthentication;\n  /** A list of host:port addresses for your Kafka brokers. */\n  bootstrapServers: Array<string>;\n  /** The name of the Kafka topic to consume messages from. */\n  topicName: string;\n};\n\n/** Union choices used by the properties above. */\ntype CustomKafkaEventSourceAuthentication =\n  | KafkaSASLAuth\n  | KafkaMTLSAuth;\n// [!code focus-end]"
  },
