  "DatabaseAccessibility": {
    "definitionName": "DatabaseAccessibility",
    "properties": [
      {
        "name": "accessibilityMode",
        "required": true,
        "shortDescription": "<p> Controls who can connect to your database.</p>\n",
        "longDescription": "<ul>\n<li><strong><code>internet</code></strong> (default): Anyone with the credentials can connect. Simplest setup, great for development.\nThe database is still protected by username/password.</li>\n<li><strong><code>vpc</code></strong>: Only your app&#39;s resources (and anything in the same VPC) can connect.\nYou can also whitelist specific IPs (e.g., your office) using <code>whitelistedIps</code>.</li>\n<li><strong><code>scoping-workloads-in-vpc</code></strong>: Most restrictive. Only resources that explicitly list this\ndatabase in their <code>connectTo</code> can reach it. Best for production.</li>\n<li><strong><code>whitelisted-ips-only</code></strong>: Only the IP addresses you list in <code>whitelistedIps</code> can connect.</li>\n</ul>\n<div class=\"highlight-wrapper\">\n  <div style=\"margin-right: 16px;line-height: 0px;\">\n  <svg xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"#ED8B00\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <path d=\"M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z\"></path>\n    <line x1=\"12\" y1=\"9\" x2=\"12\" y2=\"13\"></line>\n    <line x1=\"12\" y1=\"17\" x2=\"12.01\" y2=\"17\"></line>\n  </svg>\n  </div>\n  <div><p>Aurora Serverless engines only support <code>vpc</code> or <code>scoping-workloads-in-vpc</code>.</p>\n</div>\n</div>",
        "defaultValue": "internet",
        "typeInfo": {
          "kind": "primitive",
          "types": [
            "string"
          ],
          "enumValues": [
            "internet",
            "scoping-workloads-in-vpc",
            "vpc",
            "whitelisted-ips-only"
          ]
        }
      },
      {
        "name": "forceDisablePublicIp",
        "required": false,
        "shortDescription": "<p> Remove the database&#39;s public IP entirely (VPC-only access).</p>\n",
        "longDescription": "<div class=\"highlight-wrapper\">\n  <div style=\"margin-right: 16px;line-height: 0px;\">\n  <svg xmlns=\"http://www.w3.org/2000/svg\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"#ED8B00\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <path d=\"M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z\"></path>\n    <line x1=\"12\" y1=\"9\" x2=\"12\" y2=\"13\"></line>\n    <line x1=\"12\" y1=\"17\" x2=\"12.01\" y2=\"17\"></line>\n  </svg>\n  </div>\n  <div><p>For Aurora, this can only be set at creation time and cannot be changed later.</p>\n</div>\n</div>",
        "typeInfo": {
          "kind": "primitive",
          "types": [
            "boolean"
          ]
        }
      },
      {
        "name": "whitelistedIps",
        "required": false,
        "shortDescription": "<p> IP addresses or CIDR ranges allowed to connect (e.g., <code>203.0.113.50/32</code>).</p>\n",
        "longDescription": "<ul>\n<li>In <code>vpc</code>/<code>scoping-workloads-in-vpc</code>: adds external IPs on top of VPC access (e.g., your office).</li>\n<li>In <code>whitelisted-ips-only</code>: only these IPs can connect.</li>\n<li>No effect in <code>internet</code> mode.</li>\n</ul>\n",
        "typeInfo": {
          "kind": "array",
          "itemType": {
            "kind": "primitive",
            "types": [
              "string"
            ]
          }
        }
      }
    ],
    "stats": {
      "requiredCount": 1,
      "optionalCount": 2
    },
    "typeDeclaration": "// [!code focus-start]\ntype DatabaseAccessibility = {\n  /** Controls who can connect to your database. */\n  accessibilityMode: \"internet\" | \"scoping-workloads-in-vpc\" | \"vpc\" | \"whitelisted-ips-only\";\n  /** Remove the database&#39;s public IP entirely (VPC-only access). */\n  forceDisablePublicIp?: boolean;\n  /** IP addresses or CIDR ranges allowed to connect (e.g., 203.0.113.50/32). */\n  whitelistedIps?: Array<string>;\n};\n// [!code focus-end]"
  },
