        "name": "terminationProtection",
        "required": false,
        "shortDescription": "<p> Prevents accidental stack deletion. Must be disabled before you can delete.</p>\n",
        "longDescription": "<p>Recommended for production stacks. To delete a protected stack, first deploy with\n<code>terminationProtection: false</code>, then run the delete command.</p>\n",
