    "typeDeclaration": "// [!code focus-start]\ntype EmailConfiguration = {\n  /** From address */\n  from?: string;\n  /** Reply-to address */\n  replyToEmailAddress?: string;\n  /** SES identity to send emails from */\n  sesAddressArn?: string;\n};\n// [!code focus-end]"
