  "LbRedirect": {
    "definitionName": "LbRedirect",
    "properties": [
      {
        "name": "properties",
        "required": true,
        "shortDescription": "<p> Configures where to redirect the request.</p>\n",
        "longDescription": "<p>A redirect changes the URI, which has the format: <code>protocol://hostname:port/path?query</code>.\nUnmodified URI components will retain their original values.</p>\n<p>To avoid redirect loops, ensure that you sufficiently modify the URI.\nYou can reuse URI components with the following keywords: <code>#{protocol}</code>, <code>#{host}</code>, <code>#{port}</code>, <code>#{path}</code> (the leading <code>/</code> is removed), and <code>#{query}</code>.</p>\n<p>For example, you can change the path to <code>/new/#{path}</code>, the hostname to <code>example.#{host}</code>, or the query to <code>#{query}&value=xyz</code>.</p>\n",
        "typeInfo": {
          "kind": "reference",
          "typeName": "LbRedirectProperties"
        }
      }
    ],
    "stats": {
      "requiredCount": 1,
      "optionalCount": 0
    },
    "typeDeclaration": "import type { LbRedirectProperties } from 'stacktape';\n\n// [!code focus-start]\ntype LbRedirect = {\n  /** Configures where to redirect the request. */\n  properties: LbRedirectProperties;\n};\n// [!code focus-end]"
  },
