    "definitionName": "MfaConfiguration",
    "properties": [
      {
        "name": "enabledTypes",
        "required": false,
        "shortDescription": "<p> Enabled MFA factor types</p>\n",
        "longDescription": "<p>Chooses which MFA methods users can use:</p>\n<ul>\n<li><code>SMS</code>: One‑time codes are sent via text message. Requires an SNS role so Cognito can send SMS.</li>\n<li><code>SOFTWARE_TOKEN</code>: Time‑based one‑time codes from an authenticator app.</li>\n<li><code>EMAIL_OTP</code>: Codes are sent by email. AWS requires that you configure a developer email sending identity\n(which Stacktape does when you provide <code>emailConfiguration.sesAddressArn</code>).</li>\n</ul>\n<p>These values are mapped to Cognito&#39;s <code>EnabledMfas</code> setting (<code>SMS_MFA</code>, <code>SOFTWARE_TOKEN_MFA</code>, <code>EMAIL_OTP</code>),\nwhose behavior is described in\n<a href=\"https://docs.aws.amazon.com/AWSCloudFormation/latest/TemplateReference/aws-resource-cognito-userpool\" style=\"font-weight: bold;\" target=\"_blank\" rel=\"noreferrer\" onclick=\"event.stopPropagation();\">EnabledMfas in the AWS::Cognito::UserPool docs</a>.</p>\n",
        "typeInfo": {
          "kind": "array",
          "itemType": {
            "kind": "primitive",
            "types": [
              "string"
            ],
            "enumValues": [
              "EMAIL_OTP",
              "SMS",
              "SOFTWARE_TOKEN"
            ]
          }
        }
      },
      {
        "name": "status",
        "required": false,
        "shortDescription": "<p> MFA requirement</p>\n<ul>\n<li><code>OFF</code>: MFA is completely disabled.</li>\n<li><code>ON</code>: All users must complete MFA during sign‑in.</li>\n<li><code>OPTIONAL</code>: Users can opt in to MFA; it&#39;s recommended but not strictly required.</li>\n</ul>\n<p>This value configures the Cognito <code>MfaConfiguration</code> property.</p>\n",
        "longDescription": "",
        "typeInfo": {
          "kind": "primitive",
          "types": [
            "string"
          ],
          "enumValues": [
            "OFF",
            "ON",
            "OPTIONAL"
          ]
        }
      }
    ],
    "stats": {
      "requiredCount": 0,
      "optionalCount": 2
    },
    "typeDeclaration": "// [!code focus-start]\ntype MfaConfiguration = {\n  /** Enabled MFA factor types */\n  enabledTypes?: Array<\"EMAIL_OTP\" | \"SMS\" | \"SOFTWARE_TOKEN\">;\n  /** MFA requirement\n\nOFF: MFA is completely disabled.\nON: All users must complete MFA during sign‑in.\nOPTIONAL: Users can opt in to MFA; it&#39;s recommended but not strictly required.\n\nThis value configures the Cognito MfaConfiguration property. */\n  status?: \"OFF\" | \"ON\" | \"OPTIONAL\";\n};\n// [!code focus-end]"
