  "RedisAccessibility": {
    "definitionName": "RedisAccessibility",
    "properties": [
      {
        "name": "accessibilityMode",
        "required": true,
        "shortDescription": "<p> Who can connect to this cluster.</p>\n",
        "longDescription": "<ul>\n<li><strong><code>vpc</code></strong> (default): Any resource in the same VPC (functions with <code>joinDefaultVpc: true</code>, containers, batch jobs).</li>\n<li><strong><code>scoping-workloads-in-vpc</code></strong>: Only resources that list this cluster in their <code>connectTo</code>.</li>\n</ul>\n<p>Redis clusters don&#39;t have public IPs — you can&#39;t connect from your local machine directly.\nUse a bastion host for local access.</p>\n",
        "defaultValue": "vpc",
        "typeInfo": {
          "kind": "primitive",
          "types": [
            "string"
          ],
          "enumValues": [
            "scoping-workloads-in-vpc",
            "vpc"
          ]
        }
      }
    ],
    "stats": {
      "requiredCount": 1,
      "optionalCount": 0
    },
    "typeDeclaration": "// [!code focus-start]\ntype RedisAccessibility = {\n  /** Who can connect to this cluster. */\n  accessibilityMode: \"scoping-workloads-in-vpc\" | \"vpc\";\n};\n// [!code focus-end]"
  },
