  "ScheduleIntegrationProps": {
    "definitionName": "ScheduleIntegrationProps",
    "properties": [
      {
        "name": "scheduleRate",
        "required": true,
        "shortDescription": "<p> The schedule rate or cron expression.</p>\n",
        "longDescription": "<p>Examples: <code>rate(2 hours)</code>, <code>cron(0 10 * * ? *)</code></p>\n",
        "typeInfo": {
          "kind": "primitive",
          "types": [
            "string"
          ]
        }
      },
      {
        "name": "input",
        "required": false,
        "shortDescription": "A fixed JSON object to be passed as the event payload.",
        "longDescription": "If you need to customize the payload based on the event, use `inputTransformer` instead.\nYou can only use one of `input`, `inputPath`, or `inputTransformer`.\n\nExample:\n\n```yaml\ninput:\n  source: 'my-scheduled-event'\n```",
        "typeInfo": {
          "kind": "unknown"
        }
      },
      {
        "name": "inputPath",
        "required": false,
        "shortDescription": "<p> A JSONPath expression to extract a portion of the event to pass to the target.</p>\n",
        "longDescription": "<p>This is useful for forwarding only a specific part of the event payload.\nYou can only use one of <code>input</code>, <code>inputPath</code>, or <code>inputTransformer</code>.</p>\n<p>Example:</p>\n<pre><code class=\"language-yaml\">inputPath: &#39;$.detail&#39;\n</code></pre>\n",
        "typeInfo": {
          "kind": "primitive",
          "types": [
            "string"
          ]
        }
      },
      {
        "name": "inputTransformer",
        "required": false,
        "shortDescription": "<p> Customizes the event payload sent to the target.</p>\n",
        "longDescription": "<p>This allows you to extract values from the original event and use them to construct a new payload.\nYou can only use one of <code>input</code>, <code>inputPath</code>, or <code>inputTransformer</code>.</p>\n<p>Example:</p>\n<pre><code class=\"language-yaml\">inputTransformer:\n  inputPathsMap:\n    eventTime: &#39;$.time&#39;\n  inputTemplate:\n    message: &#39;This event occurred at &lt;eventTime&gt;.&#39;\n</code></pre>\n",
        "typeInfo": {
          "kind": "reference",
          "typeName": "EventInputTransformer"
        }
      }
    ],
    "stats": {
      "requiredCount": 1,
      "optionalCount": 3
    },
    "typeDeclaration": "import type { EventInputTransformer } from 'stacktape';\n\n// [!code focus-start]\ntype ScheduleIntegrationProps = {\n  /** The schedule rate or cron expression. */\n  scheduleRate: string;\n  /** A fixed JSON object to be passed as the event payload. */\n  input?: unknown;\n  /** A JSONPath expression to extract a portion of the event to pass to the target. */\n  inputPath?: string;\n  /** Customizes the event payload sent to the target. */\n  inputTransformer?: EventInputTransformer;\n};\n// [!code focus-end]"
  },
