    "typeDeclaration": "import type { SqsQueueEventBusIntegrationProps } from 'stacktape';\n\n// [!code focus-start]\ntype SqsQueueEventBusIntegration = {\n  /** Properties of the integration */\n  properties: SqsQueueEventBusIntegrationProps;\n};\n// [!code focus-end]"
