        "required": false,
        "shortDescription": "<p> Attach custom domains with auto-managed DNS records and TLS certificates.</p>\n",
        "longDescription": "<p><strong>Prerequisite:</strong> A Route 53 hosted zone for your domain must exist in your AWS account.</p>\n",
