    "typeDeclaration": "// [!code focus-start]\ntype UserPoolCustomDomainConfiguration = {\n  /** Domain Name */\n  domainName: string;\n  /** Custom Certificate ARN */\n  customCertificateArn?: string;\n  /** Disable DNS Record Creation */\n  disableDnsRecordCreation?: boolean;\n};\n// [!code focus-end]"
