  "UserPoolHooks": {
    "definitionName": "UserPoolHooks",
    "properties": [
      {
        "name": "createAuthChallenge",
        "required": false,
        "shortDescription": "<p> Create auth challenge hook</p>\n<p>Part of Cognito&#39;s custom auth flow. This trigger is used to generate a challenge (for example sending a custom OTP)\nafter <code>DefineAuthChallenge</code> decides a challenge is needed.</p>\n",
        "longDescription": "",
        "typeInfo": {
          "kind": "primitive",
          "types": [
            "string"
          ]
        }
      },
      {
        "name": "customMessage",
        "required": false,
        "shortDescription": "<p> Custom message hook</p>\n<p>Triggered whenever Cognito is about to send an email or SMS (sign‑up, verification, password reset, etc.).\nLets you fully customize message contents or dynamically choose language/branding.</p>\n<p>Value must be the ARN of a Lambda function configured to handle the &quot;Custom Message&quot; trigger.</p>\n",
        "longDescription": "",
        "typeInfo": {
          "kind": "primitive",
          "types": [
            "string"
          ]
        }
      },
      {
        "name": "defineAuthChallenge",
        "required": false,
        "shortDescription": "<p> Define auth challenge hook</p>\n<p>Also part of the custom auth flow. It decides whether a user needs another challenge, has passed, or has failed,\nbased on previous challenges and responses.</p>\n",
        "longDescription": "",
        "typeInfo": {
          "kind": "primitive",
          "types": [
            "string"
          ]
        }
      },
      {
        "name": "postAuthentication",
        "required": false,
        "shortDescription": "<p> Post-authentication hook</p>\n<p>Runs after a user has successfully authenticated. You can use this to record analytics, update last‑login timestamps,\nor block access based on additional checks.</p>\n",
        "longDescription": "",
        "typeInfo": {
          "kind": "primitive",
          "types": [
            "string"
          ]
        }
      },
      {
        "name": "postConfirmation",
        "required": false,
        "shortDescription": "<p> Post-confirmation hook</p>\n<p>Runs right after a user confirms their account (for example via email link or admin confirmation).\nThis is often used to create user records in your own database or to provision resources.</p>\n",
        "longDescription": "",
        "typeInfo": {
          "kind": "primitive",
          "types": [
            "string"
          ]
        }
      },
      {
        "name": "preAuthentication",
        "required": false,
        "shortDescription": "<p> Pre-authentication hook</p>\n<p>Invoked just before Cognito validates a user&#39;s credentials. You can use this to block sign‑in attempts\nbased on IP, device, or user state (for example, soft‑deleting an account).</p>\n",
        "longDescription": "",
        "typeInfo": {
          "kind": "primitive",
          "types": [
            "string"
          ]
        }
      },
      {
        "name": "preSignUp",
        "required": false,
        "shortDescription": "<p> Pre-sign-up hook</p>\n<p>Called before a new user is created. Useful for validating input, auto‑confirming trusted users,\nor blocking sign‑ups that don&#39;t meet your business rules.</p>\n",
        "longDescription": "",
        "typeInfo": {
          "kind": "primitive",
          "types": [
            "string"
          ]
        }
      },
      {
        "name": "preTokenGeneration",
        "required": false,
        "shortDescription": "<p> Pre-token-generation hook</p>\n<p>Runs right before Cognito issues tokens. Lets you customize token claims (for example, adding roles or flags)\nbased on external systems or additional logic.</p>\n",
        "longDescription": "",
        "typeInfo": {
          "kind": "primitive",
          "types": [
            "string"
          ]
        }
      },
      {
        "name": "userMigration",
        "required": false,
        "shortDescription": "<p> User migration hook</p>\n<p>Lets you migrate users on‑the‑fly from another user store. When someone tries to sign in but doesn&#39;t exist in Cognito,\nthis trigger can look them up elsewhere, import them, and let the sign‑in continue.</p>\n",
        "longDescription": "",
        "typeInfo": {
          "kind": "primitive",
          "types": [
            "string"
          ]
        }
      },
      {
        "name": "verifyAuthChallengeResponse",
        "required": false,
        "shortDescription": "<p> Verify auth challenge response hook</p>\n<p>Validates the user&#39;s response to a custom challenge (for example, checking an OTP the user provides).</p>\n",
        "longDescription": "",
        "typeInfo": {
          "kind": "primitive",
          "types": [
            "string"
          ]
        }
      }
    ],
    "stats": {
      "requiredCount": 0,
      "optionalCount": 10
    },
    "typeDeclaration": "// [!code focus-start]\ntype UserPoolHooks = {\n  /** Create auth challenge hook\nPart of Cognito&#39;s custom auth flow. This trigger is used to generate a challenge (for example sending a custom OTP)\nafter DefineAuthChallenge decides a challenge is needed. */\n  createAuthChallenge?: string;\n  /** Custom message hook\nTriggered whenever Cognito is about to send an email or SMS (sign‑up, verification, password reset, etc.).\nLets you fully customize message contents or dynamically choose language/branding.\nValue must be the ARN of a Lambda function configured to handle the &quot;Custom Message&quot; trigger. */\n  customMessage?: string;\n  /** Define auth challenge hook\nAlso part of the custom auth flow. It decides whether a user needs another challenge, has passed, or has failed,\nbased on previous challenges and responses. */\n  defineAuthChallenge?: string;\n  /** Post-authentication hook\nRuns after a user has successfully authenticated. You can use this to record analytics, update last‑login timestamps,\nor block access based on additional checks. */\n  postAuthentication?: string;\n  /** Post-confirmation hook\nRuns right after a user confirms their account (for example via email link or admin confirmation).\nThis is often used to create user records in your own database or to provision resources. */\n  postConfirmation?: string;\n  /** Pre-authentication hook\nInvoked just before Cognito validates a user&#39;s credentials. You can use this to block sign‑in attempts\nbased on IP, device, or user state (for example, soft‑deleting an account). */\n  preAuthentication?: string;\n  /** Pre-sign-up hook\nCalled before a new user is created. Useful for validating input, auto‑confirming trusted users,\nor blocking sign‑ups that don&#39;t meet your business rules. */\n  preSignUp?: string;\n  /** Pre-token-generation hook\nRuns right before Cognito issues tokens. Lets you customize token claims (for example, adding roles or flags)\nbased on external systems or additional logic. */\n  preTokenGeneration?: string;\n  /** User migration hook\nLets you migrate users on‑the‑fly from another user store. When someone tries to sign in but doesn&#39;t exist in Cognito,\nthis trigger can look them up elsewhere, import them, and let the sign‑in continue. */\n  userMigration?: string;\n  /** Verify auth challenge response hook\nValidates the user&#39;s response to a custom challenge (for example, checking an OTP the user provides). */\n  verifyAuthChallengeResponse?: string;\n};\n// [!code focus-end]"
  },
